<?php namespace App\Http\Controllers\Expense;
use App\Http\Controllers\Controller; use App\Models\Ecommerce\StoreLocation; use App\Models\Expense; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Validation\Rule;
class BranchController extends Controller { public function index(Request $r){return $this->respond(StoreLocation::query()->when($r->search,fn($q,$s)=>$q->where(fn($x)=>$x->where('name','like',"%$s%")->orWhere('code','like',"%$s%")))->orderByDesc('is_default')->orderBy('sort_order')->paginate($r->integer('per_page',15)));} public function active(){return $this->respond(StoreLocation::where('is_active',true)->orderByDesc('is_default')->orderBy('sort_order')->get());} public function store(Request $r){$data=$this->validateData($r); return DB::transaction(function()use($data){if($data['is_default']??false) StoreLocation::where('is_default',true)->update(['is_default'=>false]); $branch=StoreLocation::create($data+['is_active'=>$data['is_active']??true]); if(!$branch->is_active&&$branch->is_default) abort(422,'Inactive branch cannot be default.'); return $this->respond($branch,'Branch created successfully.',true,201);});} public function update(Request $r,StoreLocation $branch){$data=$this->validateData($r,$branch); if(($data['is_active']??$branch->is_active)===false&&$branch->is_default&&!($data['is_default']??false)) return $this->respondError('Assign another active default branch first.',422); return DB::transaction(function()use($data,$branch){if($data['is_default']??false){if(($data['is_active']??$branch->is_active)===false) abort(422,'Inactive branch cannot be default.'); StoreLocation::whereKeyNot($branch->id)->where('is_default',true)->update(['is_default'=>false]);}$branch->update($data);return $this->respond($branch,'Branch updated successfully.');});} public function destroy(StoreLocation $branch){if($branch->is_default)return $this->respondError('Assign another default branch first.',422);if(Expense::where('store_location_id',$branch->id)->exists())return $this->respondError('Referenced branches cannot be deleted; deactivate it instead.',422);$branch->delete();return $this->respond(null,'Branch deleted successfully.');} private function validateData(Request $r,?StoreLocation $b=null):array{return $r->validate(['code'=>['required','string','max:50',Rule::unique('store_locations','code')->ignore($b?->id)],'name'=>['required','string','max:150'],'address_line1'=>['required','string','max:255'],'address_line2'=>['nullable','string','max:255'],'city'=>['required','string','max:100'],'state'=>['required','string','max:100'],'postcode'=>['required','string','max:20'],'country'=>['nullable','string','max:100'],'phone'=>['nullable','string','max:30'],'email'=>['nullable','email','max:255'],'is_active'=>['sometimes','boolean'],'is_default'=>['sometimes','boolean'],'sort_order'=>['nullable','integer','min:0']]);}}
